+            id: "evt-inbound",
+            event_type: "call.initiated",
+            payload: {
+              call_control_id: "call-1",
+              direction: "incoming",
+              from: "+15551111111",
+              to: "+15550000000",
+            },
+          },
+        }),
+      }),
+    );
